  static String translate(BuildContext context, String key) {
    if (context == null) return key;
    final locale = Localizations.localeOf(context).languageCode;
    return _translations[locale]?[key] ?? _translations['hi']?[key] ?? _translations['en']?[key] ?? key;
  }

  // Dynamic Translation for AI Responses
  static Future<String> translateDynamic(String text, String targetLang) async {
    if (targetLang == 'en' || text.isEmpty) return text;
    // For now, return a simulated translated string indicating the target language
    // In production, integrate Google Cloud Translation API here.
    return "[\$targetLang Translation Setup Completed]\\n\\n\$text";
  }
